def gen(rng, size):
    def bits(n):
        if n == 1:
            return rng.choice('01')
        return '1' + ''.join(rng.choice('01') for _ in range(n - 1))
    la = rng.randint(1, max(1, size))
    lb = rng.randint(1, max(1, size))
    return [bits(la), bits(lb)]

