var addBinary = function(a, b) {
    let i = a.length - 1, j = b.length - 1, carry = 0;
    const out = [];
    while (i >= 0 || j >= 0 || carry) {
        let total = carry;
        if (i >= 0) { total += a.charCodeAt(i) - 48; i--; }
        if (j >= 0) { total += b.charCodeAt(j) - 48; j--; }
        out.push(String(total & 1));
        carry = total >> 1;
    }
    return out.reverse().join('');
};
